from collections import deque

def bfs(graf, baslangic, hedef):
    ziyaret = set()
    kuyruk = deque([[baslangic]])

    while kuyruk:
        yol = kuyruk.popleft()
        dugum = yol[-1]
        if dugum == hedef:
            return yol
        if dugum not in ziyaret:
            ziyaret.add(dugum)
            for komsu in graf.get(dugum, []):
                kuyruk.append(list(yol) + [komsu])
    return None

